targets.query:
from(bucket: "cranepdm_kpis")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r["_measurement"] == "crane_movement")
  |> filter(fn: (r) => r["crane_id"] == "${Crane_ID}")
  |> filter(fn: (r) => r["_field"] == "duration_s" or r["_field"] == "shock_penalty")
  |> pivot(rowKey:["_time"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
      "0. 주행 시간(s)": if exists r.duration_s then r.duration_s else 0.0,
      "1. 평균 충격량": if exists r.shock_penalty then r.shock_penalty else 1.0
  }))

from(bucket: "cranepdm_kpis")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r["_measurement"] == "crane_movement")
  |> filter(fn: (r) => r["crane_id"] == "${Crane_ID}")
  |> filter(fn: (r) => r["_field"] == "peak_order" or r["_field"] == "peak_shock")
  |> pivot(rowKey:["_time"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
      "0. Max order Speed": if exists r.peak_order then r.peak_order else 0.0,
      "1. Peak Shock Penalty": if exists r.peak_shock then r.peak_shock else 1.0
  }))
